import React from "react";

const tabs = [
  { key: "now", label: "Now", icon: "🏠" },
  { key: "community", label: "Community", icon: "💬" },
  { key: "chat", label: "Chat", icon: "🤖" },
];

export default function BottomBar({ active = "now", onSelect = () => {} }) {
  return (
    <nav className="fixed bottom-0 left-0 right-0 z-50">
      <div className="mx-auto max-w-xl">
        <div
          className="
            mx-3 mb-3 rounded-2xl border border-white/10
            bg-black/50 backdrop-blur-md shadow-lg
            flex items-center justify-between px-3 py-2
          "
        >
          {tabs.map((t) => {
            const isActive = active === t.key;
            return (
              <button
                key={t.key}
                onClick={() => onSelect(t.key)}
                className={`
                  flex flex-col items-center justify-center gap-0.5 px-3 py-1
                  text-[11px] transition
                  ${isActive ? "text-purple-400" : "text-white/80"}
                  hover:text-purple-300 active:scale-95
                `}
                aria-current={isActive ? "page" : undefined}
              >
                <span className="text-xl leading-none">{t.icon}</span>
                <span className="leading-none">{t.label}</span>
              </button>
            );
          })}
        </div>
      </div>
    </nav>
  );
}
